import java.util.List;

@Service
public class ProductSearchService {

    private final ProductSearchRepository repository;

    public ProductSearchService(ProductSearchRepository repository) {
        this.repository = repository;
    }

    public void init() throws IOException {
        repository.createIndexIfNotExists();
    }

    public Product indexProduct(String id, ProductRequest request) throws IOException {
        return repository.indexProduct(id, request);
    }

    public Product getProduct(String id) throws IOException {
        return repository.getProduct(id);
    }

    public SearchResponse search(String query, ProductSearchFilter filter, int page, int size, String userId) throws IOException {
        SearchResponse response = repository.search(query, filter, page, size);
        SearchQuery searchQuery = new SearchQuery();
        searchQuery.setUserId(userId);
        searchQuery.setQuery(query);
        searchQuery.setFilters(filter == null ? null : filter.toString());
        searchQuery.setSearchedAt(Instant.now());
        searchQuery.setResultCount((int) response.getTotal());
        repository.saveSearchQuery(searchQuery);
        return response;
    }

    public List<SearchQuery> getRecentSearchQueries(String userId, int size) throws IOException {
        return repository.getRecentSearchQueries(userId, size);
    }
}

package com.example.ecomsearch.controller;

import com.example.ecomsearch.dto.ProductRequest;
import com.example.ecomsearch.dto.ProductSearchFilter;
import com.example.ecomsearch.dto.SearchResponse;
import com.example.ecomsearch.model.Product;
import com.example.ecomsearch.model.SearchQuery;
import com.example.ecomsearch.service.ProductSearchService;
import org.springframework.web.bind.annotation.*;

import javax.annotation.PostConstruct;
import java.io.IOException;
import java.util.List;
import java.util.UUID;

@RestController
@RequestMapping("/api")
public class ProductSearchController {

    private final ProductSearchService service;

    public ProductSearchController(ProductSearchService service) {
        this.service = service;
    }

    @PostConstruct
    public void init() throws IOException {
        service.init();
    }

    @PostMapping("/products")
    public Product indexProduct(@RequestBody ProductRequest request) throws IOException {
        String id = UUID.randomUUID().toString();
        return service.indexProduct(id, request);
    }

    @GetMapping("/products/{id}")
    public Product getProduct(@PathVariable String id) throws IOException {
        return service.getProduct(id);
    }

    @GetMapping("/search")
    public SearchResponse search(@RequestParam(required = false) String q,
                                 @ModelAttribute ProductSearchFilter filter,
                                 @RequestParam(defaultValue = "0") int page,
                                 @RequestParam(defaultValue = "10") int size,
                                 @RequestParam(required = false, defaultValue = "anonymous") String userId) throws IOException {
        return service.search(q, filter, page, size, userId);
    }

    @GetMapping("/search-queries/{userId}")
    public List<SearchQuery> recentSearchQueries(@PathVariable String userId,
                                                 @RequestParam(defaultValue = "10") int size) throws IOException {
        return service.getRecentSearchQueries(userId, size);
    }
}

package com.example.ecomsearch.exception;

import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

@RestControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(Exception.class)
    public ResponseEntity<String> handle(Exception ex) {
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(ex.getMessage());
    }
}

package com.example.ecomsearch;

import org.springframework.boot.builder.SpringApplicationBuilder;
import org.springframework.boot.web.servlet.support.SpringBootServletInitializer;

public class ServletInitializer extends SpringBootServletInitializer {
    @Override
    protected SpringApplicationBuilder configure(SpringApplicationBuilder application) {
        return application.sources(EcomSearchApplication.class);
    }
}

package com.example.ecomsearch;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.boot.CommandLineRunner;
import com.example.ecomsearch.service.ProductSearchService;

@Configuration
public class StartupConfig {
    @Bean
    public CommandLineRunner commandLineRunner(ProductSearchService service) {
        return args -> service.init();
    }
}